#include <stdio.h>
#define MOD 1000000007
int main() {
    int T, N, M, s;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &M, &s);
        s--;
        int A[M];
        for (int i = 0; i < M; i++) {
            scanf("%d", &A[i]);
        }
        int dp[N][M + 1];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j <= M; j++) {
                dp[i][j] = 0;
            }
        }
        dp[s][0] = 1;
        for (int j = 1; j <= M; j++) {
            for (int i = 0; i < N; i++) {
                if (dp[i][j - 1] > 0) {
                    if (i - A[j - 1] >= 0) {
                        dp[i - A[j - 1]][j] = (dp[i - A[j - 1]][j] + dp[i][j - 1]) % MOD;
                    }
                    if (i + A[j - 1] < N) {
                        dp[i + A[j - 1]][j] = (dp[i + A[j - 1]][j] + dp[i][j - 1]) % MOD;
                    }
                }
            }
        }
        for (int i = 0; i < N; i++) {
            printf("%d ", dp[i][M]);
        }
        printf("\n");
    }
    return 0;
}

