import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int s = sc.nextInt() - 1;
            int[] A = new int[M];
            for (int i = 0; i < M; i++) {
                A[i] = sc.nextInt();
            }
            int[][] dp = new int[N][M + 1];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j <= M; j++) {
                    dp[i][j] = 0;
                }
            }
            dp[s][0] = 1;
            final int MOD = 1000000007;
            for (int j = 1; j <= M; j++) {
                for (int i = 0; i < N; i++) {
                    if (dp[i][j - 1] > 0) {
                        if (i - A[j - 1] >= 0) {
                            dp[i - A[j - 1]][j] = (dp[i - A[j - 1]][j] + dp[i][j - 1]) % MOD;
                        }
                        if (i + A[j - 1] < N) {
                            dp[i + A[j - 1]][j] = (dp[i + A[j - 1]][j] + dp[i][j - 1]) % MOD;
                        }
                    }
                }
            }
            for (int i = 0; i < N; i++) {
                System.out.print(dp[i][M] + " ");
            }
            System.out.println();
        }
    }
}

