    let [N, M, s] = readInts();
    s--;
    let A = readInts();
    let dp = Array(N).fill(0).map(() => Array(M + 1).fill(0));
    dp[s][0] = 1;
    for (let j = 1; j <= M; j++) {
        for (let i = 0; i < N; i++) {
            if (dp[i][j - 1] > 0) {
                if (i - A[j - 1] >= 0) {
                    dp[i - A[j - 1]][j] = (dp[i - A[j - 1]][j] + dp[i][j - 1]) % MOD;
